  1→import React, { useState, useCallback } from 'react';
  2→import {
  3→  Radar, TrendingUp, TrendingDown, Eye, MessageSquare, BarChart3,
  4→  Search, Loader2, AlertTriangle, ChevronRight, ExternalLink,
  5→  ThumbsUp, ThumbsDown, Minus, RefreshCw, Sparkles, Zap, ArrowRight
  6→} from 'lucide-react';
  7→import {
  8→  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer,
  9→  BarChart, Bar, Cell, Legend
 10→} from 'recharts';
 11→import { runMonitoringScan } from '../services/ai-monitoring';
 12→import { MonitoringResult, AIEngine } from '../types/ai-monitoring';
 13→import { User } from '../types';
 14→
 15→interface AiMonitoringProps {
 16→  onBack: () => void;
 17→  onNavigate: (view: any) => void;
 18→  onDeductCredits: (amount: number) => boolean;
 19→  user: User | null;
 20→}
 21→
 22→const ENGINE_COLORS: Record<AIEngine, string> = {
 23→  ChatGPT: '#10b981',
 24→  Claude: '#a855f7',
 25→  Perplexity: '#3b82f6',
 26→  Gemini: '#f59e0b',
 27→};
 28→
 29→const ENGINE_BG: Record<AIEngine, string> = {
 30→  ChatGPT: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
 31→  Claude: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
 32→  Perplexity: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
 33→  Gemini: 'bg-amber-500/10 text-amber-400 border-amber-500/20',
 34→};
 35→
 36→const SENTIMENT_CONFIG = {
 37→  positive: { icon: ThumbsUp, color: 'text-emerald-400', bg: 'bg-emerald-500/10', label: 'Positif' },
 38→  neutral: { icon: Minus, color: 'text-gray-400', bg: 'bg-gray-500/10', label: 'Neutre' },
 39→  negative: { icon: ThumbsDown, color: 'text-red-400', bg: 'bg-red-500/10', label: 'Negatif' },
 40→};
 41→
 42→const CREDIT_COST = 5;
 43→
 44→const AiMonitoring: React.FC<AiMonitoringProps> = ({ onBack, onNavigate, onDeductCredits, user }) => {
 45→  const [brandName, setBrandName] = useState('');
 46→  const [url, setUrl] = useState('');
 47→  const [period, setPeriod] = useState<'7d' | '30d' | '90d'>('30d');
 48→  const [isScanning, setIsScanning] = useState(false);
 49→  const [result, setResult] = useState<MonitoringResult | null>(null);
 50→  const [error, setError] = useState<string | null>(null);
 51→
 52→  const handleScan = useCallback(async () => {
 53→    if (!brandName.trim() || !url.trim()) {
 54→      setError('Veuillez saisir un nom de marque et une URL.');
 55→      return;
 56→    }
 57→
 58→    const credited = onDeductCredits(CREDIT_COST);
 59→    if (!credited) return;
 60→
 61→    setError(null);
 62→    setIsScanning(true);
 63→
 64→    try {
 65→      const data = await runMonitoringScan(brandName.trim(), url.trim(), period);
 66→      setResult(data);
 67→    } catch (err) {
 68→      setError('Erreur lors du scan. Veuillez reessayer.');
 69→      console.error(err);
 70→    } finally {
 71→      setIsScanning(false);
 72→    }
 73→  }, [brandName, url, period, onDeductCredits]);
 74→
 75→  const handleRescan = useCallback(async () => {
 76→    if (!result) return;
 77→
 78→    const credited = onDeductCredits(CREDIT_COST);
 79→    if (!credited) return;
 80→
 81→    setIsScanning(true);
 82→    try {
 83→      const data = await runMonitoringScan(result.brandName, result.url, period);
 84→      setResult(data);
 85→    } catch (err) {
 86→      setError('Erreur lors du rescan.');
 87→    } finally {
 88→      setIsScanning(false);
 89→    }
 90→  }, [result, period, onDeductCredits]);
 91→
 92→  // ── Custom tooltip for Recharts ──
 93→  const CustomTooltip = ({ active, payload, label }: any) => {
 94→    if (!active || !payload || !payload.length) return null;
 95→    return (
 96→      <div className="bg-[#1a1d21] border border-white/10 rounded-xl px-4 py-3 shadow-xl">
 97→        <p className="text-xs text-gray-400 mb-2">{label}</p>
 98→        {payload.map((entry: any, index: number) => (
 99→          <p key={index} className="text-sm font-medium" style={{ color: entry.color }}>
100→            {entry.name}: {entry.value}
101→          </p>
102→        ))}
103→      </div>
104→    );
105→  };
106→
107→  // ── Render input form ──
108→  if (!result) {
109→    return (
110→      <div className="w-full px-6 py-8 animate-in fade-in duration-500">
111→        {/* Header */}
112→        <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
113→          <div className="flex items-center gap-4">
114→            <div className="p-3 rounded-2xl bg-gradient-to-br from-purple-500/20 to-violet-600/20 border border-purple-500/20">
115→              <Radar size={28} className="text-purple-400" />
116→            </div>
117→            <div>
118→              <h1 className="text-3xl font-bold text-white">Monitoring <span className="bg-gradient-to-r from-purple-400 to-violet-400 bg-clip-text text-transparent">IA</span></h1>
119→              <p className="text-sm text-gray-500 mt-1">Suivez vos citations sur ChatGPT, Claude, Perplexity & Gemini</p>
120→            </div>
121→          </div>
122→          <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1.5 rounded-full border border-purple-500/20 flex items-center gap-1.5">
123→            <Zap size={12} /> {CREDIT_COST} Gas / scan
124→          </span>
125→        </div>
126→
127→        {/* Input card */}
128→        <div className="max-w-2xl mx-auto">
129→          <div className="ninja-card p-8 space-y-6">
130→            <div className="text-center mb-2">
131→              <h2 className="text-xl font-bold text-white mb-2">Lancer un scan de monitoring</h2>
132→              <p className="text-sm text-gray-500">Analysez la presence de votre marque dans les reponses des IA generatives</p>
133→            </div>
134→
135→            {/* Brand name */}
136→            <div>
137→              <label className="block text-sm font-medium text-gray-300 mb-2">Nom de la marque</label>
138→              <input
139→                type="text"
140→                value={brandName}
141→                onChange={(e) => setBrandName(e.target.value)}
142→                placeholder="Ex: CitedBy.ai"
143→                className="w-full bg-[#111111] border border-white/[0.08] rounded-xl py-3 px-4 text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 transition-all"
144→              />
145→            </div>
146→
147→            {/* URL */}
148→            <div>
149→              <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
150→              <input
151→                type="text"
152→                value={url}
