 146→const ExportPanel: React.FC<{ code: string; title: string }> = ({ code, title }) => {
 147→  const [format, setFormat] = useState<ExportFormat>('html-raw');
 148→  const [copied, setCopied] = useState(false);
 149→
 150→  const formattedCode = wrapForFormat(code, format);
 151→
 152→  const handleCopy = () => {
 153→    navigator.clipboard.writeText(formattedCode);
 154→    setCopied(true);
 155→    setTimeout(() => setCopied(false), 2000);
 156→  };
 157→
 158→  const handleDownload = () => {
 159→    const blob = new Blob([formattedCode], { type: 'text/html' });
 160→    const url = URL.createObjectURL(blob);
 161→    const a = document.createElement('a');
 162→    a.href = url;
 163→    a.download = `${title.replace(/[^a-zA-Z0-9]/g, '-').toLowerCase()}.html`;
 164→    document.body.appendChild(a);
 165→    a.click();
 166→    document.body.removeChild(a);
 167→    URL.revokeObjectURL(url);
 168→  };
 169→
 170→  const formatOptions: { id: ExportFormat; label: string }[] = [
 171→    { id: 'html-raw', label: 'HTML brut' },
 172→    { id: 'wordpress', label: 'WordPress Shortcode' },
 173→    { id: 'webflow', label: 'Webflow Embed' },
 174→  ];
