 181→        </div>
 182→        {/* Format selector */}
 183→        <div className="flex gap-1.5">
 184→          {formatOptions.map(opt => (
 185→            <button key={opt.id} onClick={() => setFormat(opt.id)}
 186→              className={`px-3 py-1.5 text-[11px] font-medium rounded-lg transition-all ${
 187→                format === opt.id
 188→                  ? 'bg-purple-500/20 text-purple-400 border border-purple-500/30'
