 2→import { AnalysisResult } from '../types';
 3→
 4→const DB_KEY = 'citedby_analysis_db';
 5→
 6→export const db = {
 7→  // Retrieve all analysis records
 8→  getAll: (): AnalysisResult[] => {
 9→    if (typeof window === 'undefined') return [];
10→    try {
11→      const item = localStorage.getItem(DB_KEY);
12→      return item ? JSON.parse(item) : [];
13→    } catch (error) {
14→      console.error('Error reading from DB', error);
15→      return [];
16→    }
17→  },
18→
19→  // Save a new analysis record
20→  add: (analysis: AnalysisResult) => {
21→    const current = db.getAll();
22→    // Add to beginning of list
23→    const updated = [analysis, ...current];
24→    localStorage.setItem(DB_KEY, JSON.stringify(updated));
25→    return updated;
26→  },
27→
28→  // Update an existing record (e.g. unlocked robots.txt)
29→  update: (index: number, updatedData: Partial<AnalysisResult>) => {
30→    const current = db.getAll();
31→    if (current[index]) {
32→      current[index] = { ...current[index], ...updatedData };
33→      localStorage.setItem(DB_KEY, JSON.stringify(current));
34→    }
35→    return current;
36→  },
37→
38→  // Clear database
39→  clear: () => {
40→    localStorage.removeItem(DB_KEY);
41→    return [];
42→  },
43→  
44→  // Helper to extract unique projects (domains) from history
45→  getProjectsFromHistory: (history: AnalysisResult[]) => {
46→    const uniqueMap = new Map<string, AnalysisResult>();
47→    
48→    // Sort by date ascending to ensure we capture the latest state eventually, 
49→    // or descending and check existence.
50→    // Let's iterate and keep the latest analysis for the project metadata.
51→    history.forEach(item => {
52→        try {
53→            const host = new URL(item.url).hostname;
54→            if (!uniqueMap.has(host) || new Date(item.timestamp) > new Date(uniqueMap.get(host)!.timestamp)) {
55→                uniqueMap.set(host, item);
56→            }
57→        } catch(e) {}
58→    });
59→    
60→    return Array.from(uniqueMap.values()).map((analysis, index) => {
61→        const hostname = new URL(analysis.url).hostname;
62→        return {
63→            id: `proj_${hostname}`, // ID stable based on hostname
64→            name: hostname,
65→            domain: analysis.url, // Latest URL
66→            status: 'active' as const,
67→            lastRun: analysis.timestamp,
68→            visibilityScore: analysis.globalScore,
69→            trend: analysis.globalScore > 70 ? 12 : (analysis.globalScore > 50 ? 5 : -5),
70→            nextRun: new Date(new Date(analysis.timestamp).getTime() + 86400000 * 7).toISOString()
71→        };
72→    });
73→  }
74→};
